}}<includeonly>{{#switch:{{NAMESPACE}}
||Talk={{DMC|Articles to be merged|from|{{{date|}}}|All articles to be merged}}
|User|User talk=
|#default={{#if:{{{demospace|}}}||{{DMC|||Miscellany to be merged}}}}}}{{Merge partner|{{{1|}}}}}</includeonly>
}}<noinclude>
